'use strict';
var fs = require('fs');
var path = require('path');
var template = path.join(__dirname,'template.js');
var content = fs.readFileSync(template,'utf8');  
module.exports = function(grunt,options) {
  var tcontent = content.replace(/\{\{output\}\}/g, options.outf)
  .replace(/\{\{id\}\}/g,options.id || 'modules')
  .replace(/\{\{rootLib\}\}/g,path.join(__dirname,'..'))
  .replace(/\{\{mislead\}\}/g,options.mislead || false)
  .replace(/\{\{uglify\}\}/g,options.uglify || false)
  var gruntfile = path.join(options.tmp,'Gruntfile.js');
  fs.writeFileSync(gruntfile,tcontent);
  return gruntfile;
}